bash_commands.command:
python3 << 'EOF'
import ast

with open('django/middleware/ratelimit.py', 'r') as f:
    tree = ast.parse(f.read())

# Find the class definition
for node in ast.walk(tree):
    if isinstance(node, ast.ClassDef) and node.name == 'RateLimitMiddleware':
        print(f"✓ Class: {node.name}")

        # Check methods
        methods = [m.name for m in node.body if isinstance(m, ast.FunctionDef)]
        print(f"✓ Methods: {', '.join(methods)}")

        # Verify it has the required methods
        required_methods = ['__init__', 'process_request', 'get_client_ip', 'clean_expired_entries']
        for method in required_methods:
            if method in methods:
                print(f"  ✓ {method}")
            else:
                print(f"  ✗ Missing: {method}")

# Check imports
imports_found = []
for node in ast.walk(tree):
    if isinstance(node, ast.Import):
        for alias in node.names:
            imports_found.append(alias.name)
    elif isinstance(node, ast.ImportFrom):
        for alias in node.names:
            imports_found.append(f"{node.module}.{alias.name}")

print(f"\n✓ Imports: {', '.join(imports_found)}")
EOF

